import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListToolsRequestSchema
} from "@modelcontextprotocol/sdk/types.js";

// Fetch the API Token from local environment variables
const CRM_API_KEY = process.env.CRM_API_KEY;
const CRM_API_URL = process.env.CRM_API_URL || "https://api.crm.internal/v1";

if (!CRM_API_KEY) {
  console.error("Warning: CRM_API_KEY environment variable is not defined");
}

const server = new Server(
  {
    name: "crm-gateway-mcp",
    version: "1.0.0"
  },
  {
    capabilities: {
      tools: {}
    }
  }
);

// Register tools
server.setRequestHandler(ListToolsRequestSchema, async () => {
  return {
    tools: [
      {
        name: "get_crm_contact",
        description: "Retrieves CRM contact profile details by email address",
        inputSchema: {
          type: "object",
          properties: {
            email: {
              type: "string",
              description: "The email address of the customer contact"
            }
          },
          required: ["email"]
        }
      }
    ]
  };
});

// Handle execution
server.setRequestHandler(CallToolRequestSchema, async (request) => {
  if (request.params.name === "get_crm_contact") {
    const email = request.params.arguments?.email;
    if (!email || typeof email !== "string") {
      throw new Error("Email parameter is required and must be a string");
    }

    try {
      const response = await fetch(`${CRM_API_URL}/contacts?email=${encodeURIComponent(email)}`, {
        headers: {
          "Authorization": `Bearer ${CRM_API_KEY}`,
          "Accept": "application/json"
        }
      });

      if (!response.ok) {
        throw new Error(`CRM API responded with status: ${response.status}`);
      }

      const data = await response.json();

      // Filter sensitive details out to preserve context window and privacy
      const filteredData = {
        id: data.id,
        name: data.name,
        company: data.company,
        status: data.status,
        lastContacted: data.last_contacted
      };

      return {
        content: [
          {
            type: "text",
            text: JSON.stringify(filteredData)
          }
        ]
      };
    } catch (error: any) {
      return {
        content: [
          {
            type: "text",
            text: `Failed to query contact. API Error: ${error.message}`
          }
        ],
        isError: true
      };
    }
  }
  throw new Error("Tool not found");
});

const transport = new StdioServerTransport();
await server.connect(transport);
